/* Create a SAS data set with the HIV survival data */
data hiv_survival;
   input id entry_date : date9. end_date : date9. drug_addict censor;
   datalines;
1 01JAN2010 30JUN2012 1
2 01JAN2011 31DEC2012 0
3 01JAN2012 31DEC2013 1
4 01JAN2013 31DEC2014 0
5 01JAN2014 31DEC2015 1
;
run;

/* Calculate the length of survival using the exponential distribution */
proc lifetest data=hiv_survival method=exponential;
   time end_date* censor(1);
   strata drug_addict;
run;
```

